rows = []
for chapter, chapter_data in chapters.items():
    items = chapter_data['items']
    if len(items) != 7:
        raise SystemExit(f'Chapter {chapter} does not have 7 items')

    meaning_pool = [item['meaning'] for item in items]
    synthesis_pool = [item['synthesis'] for item in items]
    advanced_pool = [item['advanced'] for item in items]

    for index, item in enumerate(items):
        rows.append({
            'book_number': 58,
            'chapter': chapter,
            'difficulty_stage': 1,
            'prompt': item['direct_prompt'],
            'choices_json': [item['answer'], *item['wrongs']],
            'correct_answer': item['answer'],
            'explanation': f"{item['verse']} supports this directly."
        })

        wrong2 = [text for text in meaning_pool if text != item['meaning']][:3]
        rows.append({
            'book_number': 58,
            'chapter': chapter,
            'difficulty_stage': 2,
            'prompt': f"In context, what does {item['verse']} emphasize?",
            'choices_json': [item['meaning'], *wrong2],
            'correct_answer': item['meaning'],
            'explanation': f"This is the point made in context at {item['verse']}."
        })

        wrong3 = [text for text in meaning_pool if text != item['meaning']][1:4]
        rows.append({
            'book_number': 58,
            'chapter': chapter,
            'difficulty_stage': 3,
            'prompt': f"What is the best contextual significance of {item['verse']} in Hebrews {chapter}?",
            'choices_json': [item['meaning'], *wrong3],
            'correct_answer': item['meaning'],
            'explanation': f"The surrounding argument supports this significance at {item['verse']}."
        })

        wrong4 = [text for text in synthesis_pool if text != item['synthesis']][:3]
        rows.append({
            'book_number': 58,
            'chapter': chapter,
            'difficulty_stage': 4,
            'prompt': f"How does {item['verse']} function in the broader argument of Hebrews {chapter}?",
            'choices_json': [item['synthesis'], *wrong4],
            'correct_answer': item['synthesis'],
            'explanation': f"This synthesis fits the chapter's broader argument around {item['verse']}."
        })

        wrong5 = [text for text in advanced_pool if text != item['advanced']][:3]
        rows.append({
            'book_number': 58,
            'chapter': chapter,
            'difficulty_stage': 5,
            'prompt': f"What is the strongest theological reading of {item['verse']} within Hebrews {chapter}?",
            'choices_json': [item['advanced'], *wrong5],
            'correct_answer': item['advanced'],
            'explanation': f"This theological reading is grounded in {item['verse']} and its chapter context."
        })

rows = sorted(rows, key=lambda row: (row['chapter'], row['difficulty_stage'], row['prompt']))
if len(rows) != 455:
    raise SystemExit(f'Expected 455 rows, got {len(rows)}')

bucket_counts = {}
for row in rows:
    if set(row.keys()) != {'book_number', 'chapter', 'difficulty_stage', 'prompt', 'choices_json', 'correct_answer', 'explanation'}:
        raise SystemExit('Row keys mismatch')
    if len(row['choices_json']) != 4:
        raise SystemExit('choices_json length mismatch')
    if row['correct_answer'] not in row['choices_json']:
        raise SystemExit('correct answer missing from choices')
    key = (row['chapter'], row['difficulty_stage'])
    bucket_counts[key] = bucket_counts.get(key, 0) + 1

if len(bucket_counts) != 65 or any(count != 7 for count in bucket_counts.values()):
    raise SystemExit(f'Bucket problem: {bucket_counts}')

output_path = Path('quiz-questions/hebrews.json')
output_path.write_text(json.dumps(rows, ensure_ascii=True, indent=2) + '\n', encoding='utf-8')
print(json.dumps({'rows': len(rows), 'buckets': len(bucket_counts), 'min_bucket': min(bucket_counts.values()), 'max_bucket': max(bucket_counts.values())}))
